                  />
                </div>
                <div className="form-group">
                  <label>Description</label>
                  <textarea
                    value={privacyData.protectionDesc3}
                    onChange={(e) => setPrivacyData({...privacyData, protectionDesc3: e.target.value})}
                    className="form-textarea"
                    rows="2"
                  />
                </div>
              </div>
            </div>
          </div>
        );

      default:
        return null;
    }
  };

  if (loading) {
    return (
      <div className="privacy-editor">
        <div className="loading-container">
          <p>⏳ Chargement des données...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="privacy-editor">
      <div className="editor-header">
        <div className="header-content">
          <h2>🔒 Édition de la Politique de Confidentialité</h2>
          <p>Modifiez le contenu de votre page de confidentialité</p>
        </div>
      </div>

      {error && (
        <div className="error-banner">
          <span>⚠️</span>
          <p>{error}</p>
          <button onClick={() => setError(null)}>✕</button>
        </div>
      )}

      <div className="editor-layout">
        <div className="editor-sidebar">
          <div className="sidebar-header">
            <span>📑 Sections</span>
          </div>
          <div className="sidebar-nav">
            {sections.map(section => (
              <button
                key={section.id}
                className={`nav-item ${activeSection === section.id ? 'active' : ''}`}
                onClick={() => setActiveSection(section.id)}
              >
                <span className="nav-icon">{section.icon}</span>
                <span className="nav-text">{section.name}</span>
              </button>
            ))}
          </div>
        </div>

        <div className="editor-main">
          <div className="section-header">
            <h3>
              {sections.find(s => s.id === activeSection)?.icon}
              {sections.find(s => s.id === activeSection)?.name}
            </h3>
          </div>

          {renderSectionContent()}

          <div className="editor-actions">
            <button 
              className="save-btn" 
              onClick={handleSave}
              disabled={saving}
            >
              <span className="btn-icon">💾</span>
              {saving ? 'Sauvegarde...' : 'Sauvegarder'}
            </button>
            <button 
              className="reset-btn" 
              onClick={loadPrivacyData}
              disabled={saving || loading}
            >
              <span className="btn-icon">🔄</span>
              Recharger
            </button>
            {onClose && (
              <button className="close-btn" onClick={onClose}>
                <span className="btn-icon">✕</span>
                Fermer
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default PrivacyEditor;
